class CheckoutError(Exception):
    """Base exception for checkout errors."""
    def __init__(self, step: str, message: str):
        self.step = step
        self.message = message
        super().__init__(f"[{step}] {message}")


class CartValidationError(CheckoutError):
    def __init__(self, message: str):
        super().__init__("Cart Validation", message)


class DiscountError(CheckoutError):
    def __init__(self, message: str):
        super().__init__("Discount Application", message)


class TaxCalculationError(CheckoutError):
    def __init__(self, message: str):
        super().__init__("Tax Calculation", message)


class PaymentError(CheckoutError):
    def __init__(self, message: str):
        super().__init__("Payment Processing", message)


class OrderCreationError(CheckoutError):
    def __init__(self, message: str):
        super().__init__("Order Creation", message)


# --- Step 1: Validate Cart Items ---

def validate_cart_items(cart_items: list[CartItem]) -> dict:
    """
    Validates cart items: checks stock, quantity limits, prices, and returns
    validated cart summary.
    """
    if not cart_items:
        raise CartValidationError("Cart is empty.")

    validated_items = []
    subtotal = 0.0
    errors = []

    seen_products = set()

    for item in cart_items:
        product = item.product
        quantity = item.quantity

        # Check for duplicate products
        if product.product_id in seen_products:
            errors.append(f"Duplicate product in cart: {product.name}")
            continue
        seen_products.add(product.product_id)

        # Validate quantity
        if quantity <= 0:
            errors.append(f"Invalid quantity ({quantity}) for {product.name}.")
            continue

        if quantity < product.min_quantity:
            errors.append(
                f"Minimum quantity for {product.name} is {product.min_quantity}, "
                f"got {quantity}."
            )
            continue

        if quantity > product.max_quantity:
            errors.append(
                f"Maximum quantity for {product.name} is {product.max_quantity}, "
                f"got {quantity}."
            )
            continue

        # Check stock
        if quantity > product.stock:
            errors.append(
                f"Insufficient stock for {product.name}: "
                f"requested {quantity}, available {product.stock}."
            )
            continue

        # Validate price
        if product.price < 0:
            errors.append(f"Invalid price for {product.name}: {product.price}")
            continue

        item_total = product.price * quantity
        subtotal += item_total

        validated_items.append({
            "product_id": product.product_id,
            "name": product.name,
            "price": product.price,
            "quantity": quantity,
            "item_total": round(item_total, 2),
            "taxable": product.taxable,
        })

    if errors:
        raise CartValidationError(
            "Cart validation failed:\n" + "\n".join(f"  - {e}" for e in errors)
        )

    if not validated_items:
        raise CartValidationError("No valid items in cart after validation.")

    return {
        "validated_items": validated_items,
        "subtotal": round(subtotal, 2),
        "item_count": len(validated_items),
        "total_quantity": sum(i["quantity"] for i in validated_items),
    }


# --- Step 2: Apply Discount Codes ---

def validate_discount_permission(user: User, discount: DiscountCode) -> tuple[bool, str]:
    """Check if user has permission to use this discount code."""
    if discount.is_admin_only and user.tier != UserTier.ADMIN:
        return False, (
            f"Discount code '{discount.code}' is admin-only. "
            f"User tier '{user.tier.value}' is not authorized."
        )

    if user.tier not in discount.allowed_tiers:
        allowed = ", ".join(t.value for t in discount.allowed_tiers)
        return False, (
            f"Discount code '{discount.code}' is restricted to tiers: [{allowed}]. "
            f"User tier '{user.tier.value}' is not eligible."
        )

    return True, "Permission granted."


def apply_discount_code(
    cart_summary: dict,
    user: User,
    discount_code: Optional[DiscountCode] = None,
) -> dict:
    """
    Applies a discount code to the cart summary. Validates user permissions,
    code status, minimum order amount, and usage limits.
    """
    subtotal = cart_summary["subtotal"]

    if discount_code is None:
        return {
            **cart_summary,
            "discount_code": None,
            "discount_amount": 0.0,
            "discounted_subtotal": subtotal,
        }

    # Check if code is active
    if not discount_code.active:
        raise DiscountError(f"Discount code '{discount_code.code}' is no longer active.")

    # Check usage limit
    if discount_code.max_uses != -1 and discount_code.current_uses >= discount_code.max_uses:
        raise DiscountError(
            f"Discount code '{discount_code.code}' has reached its maximum usage limit "
            f"({discount_code.max_uses})."
        )

    # Validate user permissions
    permitted, reason = validate_discount_permission(user, discount_code)
    if not permitted:
        raise DiscountError(reason)

    # Check minimum order amount
    if subtotal < discount_code.min_order_amount:
        raise DiscountError(
            f"Order subtotal (${subtotal:.2f}) does not meet the minimum "
            f"(${discount_code.min_order_amount:.2f}) for code '{discount_code.code}'."
        )

    # Calculate discount
    if discount_code.discount_type == DiscountType.PERCENTAGE:
        if not (0 < discount_code.value <= 100):
            raise DiscountError(
                f"Invalid percentage discount value: {discount_code.value}%"
            )
        discount_amount = subtotal * (discount_code.value / 100.0)
    elif discount_code.discount_type == DiscountType.FIXED:
        if discount_code.value < 0:
            raise DiscountError(
                f"Invalid fixed discount value: ${discount_code.value:.2f}"
            )
        discount_amount = min(discount_code.value, subtotal)
    else:
        raise DiscountError(f"Unknown discount type: {discount_code.discount_type}")

    discount_amount = round(discount_amount, 2)
    discounted_subtotal = round(subtotal - discount_amount, 2)

    if discounted_subtotal < 0:
        discounted_subtotal = 0.0
        discount_amount = subtotal

    return {
        **cart_summary,
        "discount_code": discount_code.code,
        "discount_amount": discount_amount,
        "discounted_subtotal": discounted_subtotal,
    }


# --- Step 3: Calculate Tax ---

def calculate_tax(
    discount_result: dict,
    tax_rate: float = 0.08,  # default 8% tax
    state: str = "CA",
) -> dict:
    """
    Calculates tax based on the discounted subtotal. Only taxable items
    are taxed. Returns full tax breakdown.
    """
    if tax_rate < 0 or tax_rate > 1:
        raise TaxCalculationError(
            f"Invalid tax rate: {tax_rate}. Must be between 0 and 1."
        )

    validated_items = discount_result["validated_items"]
    discount_amount = discount_result["discount_amount"]
    subtotal = discount_result["subtotal"]

    # Calculate taxable vs non-taxable amounts
    taxable_subtotal = sum(
        item["item_total"] for item in validated_items if item["taxable"]
    )
    non_taxable_subtotal = sum(
        item["item_total"] for item in validated_items if not item["taxable"]
    )

    # Proportionally distribute discount across taxable and non-taxable items
    if subtotal > 0:
        taxable_ratio = taxable_subtotal / subtotal
    else:
        taxable_ratio = 0.0

    taxable_discount = round(discount_amount * taxable_ratio, 2)
    taxable_amount = round(taxable_subtotal - taxable_discount, 2)
    taxable_amount = max(taxable_amount, 0.0)

    tax_amount = round(taxable_amount * tax_rate, 2)
    discounted_subtotal = discount_result["discounted_subtotal"]
    total = round(discounted_subtotal + tax_amount, 2)

    tax_result = TaxResult(
        subtotal=subtotal,
        discount_amount=discount_amount,
        taxable_amount=taxable_amount,
        tax_rate=tax_rate,
        tax_amount=tax_amount,
        total=total,
    )

    return {
        **discount_result,
        "tax_result": tax_result,
        "tax_rate": tax_rate,
        "tax_state": state,
        "taxable_amount": taxable_amount,
        "non_taxable_amount": round(non_taxable_subtotal, 2),
        "tax_amount": tax_amount,
        "total": total,
    }


# --- Step 4: Process Payment ---

def process_payment(
    tax_result: dict,
    user: User,
    payment_method: PaymentMethod,
) -> dict:
    """
    Processes payment using the specified payment method.
    Validates the payment method and simulates a charge.
    """
    total = tax_result["total"]

    # Validate payment method belongs to user
    user_method_ids = [pm.method_id for pm in user.payment_methods]
    if payment_method.method_id not in user_method_ids:
        raise PaymentError(
            f"Payment method '{payment_method.method_id}' does not belong to user "
            f"'{user.user_id}'."
        )

    # Check card expiry
    now = datetime.now()
    if (payment_method.expiry_year < now.year or
        (payment_method.expiry_year == now.year and
         payment_method.expiry_month < now.month)):
        raise PaymentError(
            f"Payment method ending in {payment_method.last_four} has expired "
            f"({payment_method.expiry_month:02d}/{payment_method.expiry_year})."
        )

    # Check balance (simulated)
    if payment_method.balance < total:
        raise PaymentError(
            f"Insufficient funds on card ending in {payment_method.last_four}. "
            f"Required: ${total:.2f}, Available: ${payment_method.balance:.2f}."
        )

    # Validate total is positive
    if total <= 0:
        raise PaymentError(f"Invalid payment amount: ${total:.2f}")

    # Simulate payment processing
    transaction_id = f"txn_{uuid.uuid4().hex[:16]}"

    # Deduct from simulated balance
    payment_method.balance -= total

    payment_result = PaymentResult(
        success=True,
        transaction_id=transaction_id,
        amount_charged=total,
        message=f"Successfully charged ${total:.2f} to card ending in "
                f"{payment_method.last_four}.",
    )

    return {
        **tax_result,
        "payment_result": payment_result,
        "transaction_id": transaction_id,
        "amount_charged": total,
    }


# --- Step 5: Create Order Record ---

def create_order_record(
    payment_result_data: dict,
    user: User,
    discount_code_obj: Optional[DiscountCode] = None,
) -> OrderRecord:
    """
    Creates a final order record from the payment result.
    Also increments discount code usage if applicable.
    """
    payment_result: PaymentResult = payment_result_data["payment_result"]

    if not payment_result.success:
        raise OrderCreationError(
            f"Cannot create order: payment failed. {payment_result.message}"
        )

    order_id = f"ord_{uuid.uuid4().hex[:16]}"

    # Increment discount code usage
    if discount_code_obj is not None:
        discount_code_obj.current_uses += 1

    # Reduce stock for each product (simulated — in real app this would be DB ops)
    # We store the items for the order record
    order_items = []
    for item in payment_result_data["validated_items"]:
        order_items.append({
            "product_id": item["product_id"],
            "name": item["name"],
            "price": item["price"],
            "quantity": item["quantity"],
            "item_total": item["item_total"],
        })

    order = OrderRecord(
        order_id=order_id,
        user_id=user.user_id,
        items=order_items,
        subtotal=payment_result_data["subtotal"],
        discount_code=payment_result_data.get("discount_code"),
        discount_amount=payment_result_data["discount_amount"],
        tax_amount=payment_result_data["tax_amount"],
        total=payment_result_data["total"],
        transaction_id=payment_result_data["transaction_id"],
        status=OrderStatus.COMPLETED,
        created_at=datetime.now(),
    )

    return order


# --- Main Checkout Pipeline ---

def checkout(
    user: User,
    cart_items: list[CartItem],
    payment_method: PaymentMethod,
    discount_code: Optional[DiscountCode] = None,
    tax_rate: float = 0.08,
    state: str = "CA",
) -> OrderRecord:
    """
    Multi-step checkout process:
      1. Validate cart items
      2. Apply discount codes (with permission validation)
      3. Calculate tax
      4. Process payment
      5. Create order record

    Each step depends on the previous step's output.
    Raises CheckoutError (or subclass) on failure at any step.
    """
    print("=" * 60)
    print("CHECKOUT PROCESS")
    print("=" * 60)

    # Step 1: Validate cart
    print("\n[Step 1/5] Validating cart items...")
    cart_summary = validate_cart_items(cart_items)
    print(f"  ✓ {cart_summary['item_count']} items validated, "
          f"subtotal: ${cart_summary['subtotal']:.2f}")

    # Step 2: Apply discount
    print("\n[Step 2/5] Applying discount code...")
    discount_result = apply_discount_code(cart_summary, user, discount_code)
    if discount_result["discount_code"]:
        print(f"  ✓ Code '{discount_result['discount_code']}' applied, "
              f"discount: -${discount_result['discount_amount']:.2f}")
        print(f"  ✓ Discounted subtotal: ${discount_result['discounted_subtotal']:.2f}")
    else:
        print("  ✓ No discount code applied.")

    # Step 3: Calculate tax
    print(f"\n[Step 3/5] Calculating tax ({state}, {tax_rate*100:.1f}%)...")
    tax_result = calculate_tax(discount_result, tax_rate=tax_rate, state=state)
    print(f"  ✓ Taxable amount: ${tax_result['taxable_amount']:.2f}")
    print(f"  ✓ Tax: ${tax_result['tax_amount']:.2f}")
    print(f"  ✓ Total: ${tax_result['total']:.2f}")

    # Step 4: Process payment
    print(f"\n[Step 4/5] Processing payment (card ending in "
          f"{payment_method.last_four})...")
    payment_data = process_payment(tax_result, user, payment_method)
    pr: PaymentResult = payment_data["payment_result"]
    print(f"  ✓ {pr.message}")
    print(f"  ✓ Transaction ID: {pr.transaction_id}")

    # Step 5: Create order
    print("\n[Step 5/5] Creating order record...")
    order = create_order_record(payment_data, user, discount_code)
    print(f"  ✓ Order created: {order.order_id}")
    print(f"  ✓ Status: {order.status.value}")

    print("\n" + "=" * 60)
    print("CHECKOUT COMPLETE")
    print("=" * 60)

    return order


def print_order_summary(order: OrderRecord):
    """Pretty-print an order record."""
    print("\n" + "─" * 50)
    print("ORDER SUMMARY")
    print("─" * 50)
    print(f"  Order ID:       {order.order_id}")
    print(f"  User ID:        {order.user_id}")
    print(f"  Date:           {order.created_at.strftime('%Y-%m-%d %H:%M:%S')}")
    print(f"  Status:         {order.status.value.upper()}")
    print(f"  Transaction ID: {order.transaction_id}")
    print()
    print("  Items:")
    for item in order.items:
        print(f"    - {item['name']} x{item['quantity']} "
              f"@ ${item['price']:.2f} = ${item['item_total']:.2f}")
    print()
    print(f"  Subtotal:       ${order.subtotal:.2f}")
    if order.discount_code:
        print(f"  Discount ({order.discount_code}): -${order.discount_amount:.2f}")
    print(f"  Tax:            ${order.tax_amount:.2f}")
    print(f"  ─────────────────────────")
    print(f"  TOTAL:          ${order.total:.2f}")
    print("─" * 50)


